"""Physical log line with optional upstream source metadata."""

from __future__ import annotations

from datetime import datetime

from pydantic import BaseModel, ConfigDict, Field


class PhysicalLogRecord(BaseModel):
    """One physical log line plus optional CloudWatch (or other) provenance."""

    model_config = ConfigDict(frozen=True)

    message: str
    source_event_id: str | None = None
    source_stream: str | None = None
    source_timestamp: datetime | None = None

    @classmethod
    def from_message(cls, message: str) -> PhysicalLogRecord:
        return cls(message=message)

    @classmethod
    def from_lines(cls, lines: list[str]) -> list[PhysicalLogRecord]:
        return [cls.from_message(line) for line in lines]

"""Apply upstream source metadata to parsed LogLine and validation results."""

from __future__ import annotations

from datetime import UTC, datetime

from backtrace_agent.log_source.models import LogLine
from backtrace_agent.log_source.physical_record import PhysicalLogRecord
from backtrace_agent.log_source.stage0.models import LogicalEvent
from backtrace_agent.log_source.stage3.models import ValidationResult


def attach_source_to_events(
    events: list[LogicalEvent],
    records: list[PhysicalLogRecord],
) -> list[LogicalEvent]:
    """Copy source metadata from the first physical line of each logical event."""
    enriched: list[LogicalEvent] = []
    for event in events:
        if not event.line_numbers:
            enriched.append(event)
            continue
        record = records[event.line_numbers[0] - 1]
        if record.source_event_id is None and record.source_stream is None and record.source_timestamp is None:
            enriched.append(event)
            continue
        enriched.append(
            event.model_copy(
                update={
                    "source_event_id": record.source_event_id,
                    "source_stream": record.source_stream,
                    "source_timestamp": record.source_timestamp,
                }
            )
        )
    return enriched


def enrich_log_line_from_event(log_line: LogLine, event: LogicalEvent) -> LogLine:
    """Set canonical source_* fields and prefer CloudWatch time over poll ingestion time."""
    updates: dict[str, object] = {}
    if event.source_event_id is not None:
        updates["source_event_id"] = event.source_event_id
    if event.source_stream is not None:
        updates["source_stream"] = event.source_stream
    if event.source_timestamp is not None:
        updates["source_timestamp"] = event.source_timestamp

    raw = dict(log_line.raw)
    if event.source_event_id is not None:
        raw["source_event_id"] = event.source_event_id
    if event.source_stream is not None:
        raw["source_stream"] = event.source_stream
    if event.source_timestamp is not None:
        raw["source_timestamp"] = event.source_timestamp.isoformat()
    updates["raw"] = raw

    return log_line.model_copy(update=updates)


def resolve_effective_timestamp(
    result: ValidationResult,
    event: LogicalEvent,
) -> tuple[datetime | None, str | None]:
    """Prefer CloudWatch source time when the parser fell back to ingestion time."""
    if result.effective_timestamp is None:
        return None, result.timestamp_source

    if result.timestamp_source == "ingestion_timestamp" and event.source_timestamp is not None:
        ts = event.source_timestamp
        normalized = ts if ts.tzinfo else ts.replace(tzinfo=UTC)
        return normalized, "source_timestamp"

    effective = result.effective_timestamp
    return effective if effective.tzinfo else effective.replace(tzinfo=UTC), result.timestamp_source


def enrich_validation_result(result: ValidationResult, event: LogicalEvent) -> ValidationResult:
    """Attach source metadata and stable effective timestamp after Stage 3 validation."""
    if not result.parse_success or result.log_line is None:
        return result

    line = enrich_log_line_from_event(result.log_line, event)
    if result.timestamp_source == "ingestion_timestamp" and event.source_timestamp is not None:
        line = line.model_copy(update={"timestamp": event.source_timestamp})

    effective, timestamp_source = resolve_effective_timestamp(
        result.model_copy(update={"log_line": line}),
        event,
    )
    return result.model_copy(
        update={
            "log_line": line,
            "effective_timestamp": effective,
            "timestamp_source": timestamp_source,
            "ingestion_timestamp": None
            if timestamp_source == "source_timestamp"
            else result.ingestion_timestamp,
        }
    )

