"""CloudWatch Logs FilterLogEvents integration."""

from __future__ import annotations

from datetime import UTC, datetime, timedelta
from typing import Any

import structlog

from backtrace_agent.log_source.correlation import CorrelationMethod, CorrelationStrategy
from backtrace_agent.log_source.physical_record import PhysicalLogRecord

logger = structlog.get_logger(__name__)


def query_time_bounds(
    *,
    watermark: datetime | None,
    lookback_seconds: int,
    bootstrap_seconds: int,
    end_time: datetime | None = None,
) -> tuple[datetime, datetime]:
    """Compute [start, end] for a detection poll with watermark lookback buffer."""
    end = end_time or datetime.now(UTC)
    if end.tzinfo is None:
        end = end.replace(tzinfo=UTC)
    if watermark is None:
        start = end - timedelta(seconds=bootstrap_seconds)
    else:
        wm = watermark if watermark.tzinfo else watermark.replace(tzinfo=UTC)
        start = wm - timedelta(seconds=lookback_seconds)
    return start, end


def _epoch_ms(dt: datetime) -> int:
    normalized = dt if dt.tzinfo else dt.replace(tzinfo=UTC)
    return int(normalized.timestamp() * 1000)


def _from_epoch_ms(value: int) -> datetime:
    return datetime.fromtimestamp(value / 1000.0, tz=UTC)


def build_correlation_filter_pattern(strategy: CorrelationStrategy) -> str | None:
    """Best-effort CloudWatch filter pattern for correlation (may return None)."""
    if strategy.method == CorrelationMethod.REQUEST_ID and strategy.request_id:
        return f'"{strategy.request_id}"'
    if strategy.method == CorrelationMethod.TRACE_ID and strategy.trace_id:
        return f'"{strategy.trace_id}"'
    if strategy.method == CorrelationMethod.SESSION_ID and strategy.session_id:
        return f'"{strategy.session_id}"'
    return None


class CloudWatchLogsClient:
    """Thin wrapper around logs:FilterLogEvents with pagination."""

    def __init__(
        self,
        *,
        log_group_name: str,
        region_name: str,
        boto_client: Any | None = None,
    ) -> None:
        self._log_group_name = log_group_name
        self._region_name = region_name
        self._client = boto_client

    def _get_client(self) -> Any:
        if self._client is not None:
            return self._client
        import boto3

        self._client = boto3.client("logs", region_name=self._region_name)
        return self._client

    def fetch_records(
        self,
        *,
        start_time: datetime,
        end_time: datetime,
        filter_pattern: str | None = None,
    ) -> list[PhysicalLogRecord]:
        """Fetch all log events in [start_time, end_time], paginated."""
        client = self._get_client()
        kwargs: dict[str, Any] = {
            "logGroupName": self._log_group_name,
            "startTime": _epoch_ms(start_time),
            "endTime": _epoch_ms(end_time),
            "interleaved": True,
        }
        if filter_pattern:
            kwargs["filterPattern"] = filter_pattern

        records: list[PhysicalLogRecord] = []
        next_token: str | None = None
        while True:
            if next_token:
                kwargs["nextToken"] = next_token
            elif "nextToken" in kwargs:
                del kwargs["nextToken"]

            response = client.filter_log_events(**kwargs)
            for event in response.get("events", []):
                message = event.get("message", "")
                if not message:
                    continue
                event_ts = event.get("timestamp")
                ingestion_ts = event.get("ingestionTime")
                source_ts = _from_epoch_ms(event_ts) if event_ts is not None else None
                if source_ts is None and ingestion_ts is not None:
                    source_ts = _from_epoch_ms(ingestion_ts)
                records.append(
                    PhysicalLogRecord(
                        message=message,
                        source_event_id=event.get("eventId"),
                        source_stream=event.get("logStreamName"),
                        source_timestamp=source_ts,
                    )
                )

            next_token = response.get("nextToken")
            if not next_token:
                break

        logger.info(
            "cloudwatch.fetch_complete",
            log_group=self._log_group_name,
            start_time=start_time.isoformat(),
            end_time=end_time.isoformat(),
            record_count=len(records),
            filter_pattern=filter_pattern,
        )
        return records

"""Shared helpers for turning pipeline validation results into LogLine lists."""

from __future__ import annotations

from backtrace_agent.log_source.models import LogLine
from backtrace_agent.log_source.stage3.models import ValidationResult


def field_value(line: LogLine, field: str) -> str | None:
    value = getattr(line, field, None)
    if value is not None:
        return str(value)
    raw_value = line.raw.get(field)
    if raw_value is not None:
        return str(raw_value)
    alias_map = {
        "request_id": ("requestId", "request_id"),
        "trace_id": ("traceId", "trace_id"),
        "span_id": ("spanId", "span_id"),
        "session_id": ("sessionId", "session_id"),
        "pod_name": ("podName", "pod_name"),
        "container_id": ("containerId", "container_id"),
    }
    for key in alias_map.get(field, ()):
        raw_value = line.raw.get(key)
        if raw_value is not None:
            return str(raw_value)
    return None


def validation_results_to_log_lines(
    results: list[ValidationResult],
    *,
    error_filter_field: str,
    error_filter_values: list[str],
    require_accepted: bool = True,
) -> list[LogLine]:
    """Map validation results to LogLines with optional error-level filter."""
    lines: list[LogLine] = []
    for result in results:
        if require_accepted and not result.accepted:
            continue
        if not result.parse_success or result.log_line is None:
            continue
        line = result.log_line
        field_val = field_value(line, error_filter_field)
        if field_val not in error_filter_values:
            continue
        lines.append(line)
    return lines

