        bootstrap_seconds=60,
        boto_client=mock_cw_client,
    )


@pytest.mark.asyncio
async def test_fetch_errors_since_queries_with_lookback(
    cloudwatch_source: CloudWatchLogSource,
    mock_cw_client: MagicMock,
) -> None:
    mock_cw_client.filter_log_events.return_value = {
        "events": [
            {
                "eventId": "evt-new",
                "logStreamName": "s1",
                "timestamp": int(datetime(2026, 5, 29, 17, 31, 0, tzinfo=UTC).timestamp() * 1000),
                "message": '{"timestamp":"2026-05-29T17:31:00Z","level":"ERROR","message":"new"}',
            },
            {
                "eventId": "evt-old",
                "logStreamName": "s1",
                "timestamp": int(WM.timestamp() * 1000),
                "message": '{"timestamp":"2026-05-29T17:30:42Z","level":"ERROR","message":"old"}',
            },
        ]
    }

    errors = await cloudwatch_source.fetch_errors_since(
        WM,
        error_filter_field="level",
        error_filter_values=["ERROR"],
    )

    assert len(errors) == 1
    assert errors[0].message == "new"
    assert errors[0].source_event_id == "evt-new"
    call_kwargs = mock_cw_client.filter_log_events.call_args.kwargs
    assert call_kwargs["logGroupName"] == "/ecs/target-project"
    assert call_kwargs["startTime"] == int(
        datetime(2026, 5, 29, 17, 30, 12, tzinfo=UTC).timestamp() * 1000
    )


@pytest.mark.asyncio
async def test_fetch_errors_uses_source_timestamp_when_json_lacks_timestamp(
    cloudwatch_source: CloudWatchLogSource,
    mock_cw_client: MagicMock,
) -> None:
    cw_ts = datetime(2026, 5, 29, 17, 31, 5, tzinfo=UTC)
    mock_cw_client.filter_log_events.return_value = {
        "events": [
            {
                "eventId": "evt-no-ts",
                "logStreamName": "s1",
                "timestamp": int(cw_ts.timestamp() * 1000),
                "message": '{"level":"ERROR","message":"Payment Failed"}',
            }
        ]
    }

    errors = await cloudwatch_source.fetch_errors_since(
        None,
        error_filter_field="level",
        error_filter_values=["ERROR"],
    )

    assert len(errors) == 1
    assert errors[0].timestamp == cw_ts
    assert errors[0].source_event_id == "evt-no-ts"


@pytest.mark.asyncio
async def test_fetch_lifecycle_skips_watermark_filter(
    cloudwatch_source: CloudWatchLogSource,
    mock_cw_client: MagicMock,
) -> None:
    from backtrace_agent.log_source.correlation import (
        CorrelationConfidence,
        CorrelationMethod,
        CorrelationStrategy,
    )

    mock_cw_client.filter_log_events.return_value = {
        "events": [
            {
                "eventId": "evt-info",
                "logStreamName": "s1",
                "timestamp": int(WM.timestamp() * 1000),
                "message": '{"timestamp":"2026-05-29T17:30:42Z","level":"INFO","message":"start","requestId":"req-1"}',
            },
            {
                "eventId": "evt-err",
                "logStreamName": "s1",
                "timestamp": int(WM.timestamp() * 1000),
                "message": '{"timestamp":"2026-05-29T17:30:42Z","level":"ERROR","message":"fail","requestId":"req-1"}',
            },
        ]
    }

    strategy = CorrelationStrategy(
        method=CorrelationMethod.REQUEST_ID,
        confidence=CorrelationConfidence.EXACT_REQUEST_ID,
        request_id="req-1",
    )
    lines = await cloudwatch_source.fetch_lifecycle_by_correlation(
        strategy,
        around_timestamp=WM,
        window_minutes=15,
    )

    assert len(lines) == 2
    levels = {line.level for line in lines}
    assert levels == {"INFO", "ERROR"}

